# Kill criteria monitor: evaluate all active projects against kill thresholds

from dataclasses import dataclass, field
from datetime import date
from typing import Optional

@dataclass
class KillCriterion:
    name: str
    threshold: str              # human-readable threshold
    current_value: str          # current measured value
    threshold_date: date        # when criterion must be met by
    met: bool                   # True = threshold met (DO NOT kill)
    in_remediation: bool = False
    remediation_deadline: Optional[date] = None

@dataclass
class Project:
    name: str
    tier: str
    criteria: list
    start_date: date

def evaluate_kill_status(project: Project, today: date = None) -> dict:
    if today is None:
        today = date.today()
    triggered = []
    for c in project.criteria:
        if not c.met and today >= c.threshold_date:
            if c.in_remediation and c.remediation_deadline and today <= c.remediation_deadline:
                status = "IN_REMEDIATION"
            elif c.in_remediation and c.remediation_deadline and today > c.remediation_deadline:
                status = "REMEDIATION_FAILED"
            else:
                status = "CRITERION_TRIGGERED"
            triggered.append({"criterion": c.name, "status": status})
    recommendation = "CONTINUE"
    if any(t["status"] == "REMEDIATION_FAILED" for t in triggered):
        recommendation = "SUNSET_REVIEW"
    elif triggered:
        recommendation = "START_REMEDIATION"
    return {"project": project.name, "triggered": triggered, "recommendation": recommendation}

project = Project(
    name="Customer churn prediction agent",
    tier="INVEST",
    criteria=[
        KillCriterion("Benefit realization >= 50%", "50% of $1.2M", "32% ($384K)", date(2025, 9, 1), met=False, in_remediation=True, remediation_deadline=date(2025, 11, 1)),
        KillCriterion("User adoption >= 70%", "70% of target users", "45%", date(2025, 6, 1), met=False, in_remediation=False),
    ],
    start_date=date(2025, 1, 1)
)
result = evaluate_kill_status(project, today=date(2025, 10, 15))
print(result)
